class Node {
  constructor(value) {
    this.value = value;
    this.next = null;
  }
}

class LinkedList {
  constructor() {
    this.head = null;
  }

  append(value) {
    const node = new Node(value);
    if (!this.head) {
      this.head = node;
      return;
    }
    let curr = this.head;
    while (curr.next) curr = curr.next;
    curr.next = node;
  }
}

const list = new LinkedList();
list.append(1);
list.append(2);
list.append(3);
console.log(JSON.stringify(list));`},"d2-l2":{language:"js",code:`// Stack using array
